class InspectionMission(Node):
    def __init__(self, waypoints):
        super().__init__('inspection_mission')
        self.waypoints = waypoints
        self.wp_idx = 0

    def execute(self):
        for wp in self.waypoints:
            goto_waypoint(wp)  # via MAVROS
            images = capture_burst(n=5)
            defects = defect_detector(images)
            if defects:
                hover_and_capture_hires(wp)
            log_inspection(wp.element_id, images, defects)
